import { FC } from "react";
import { AboutPageId, useScroll, WorkPageId, HomeId } from "utils/useScroll";
import { Box, Flex, Text, Heading, useBreakpointValue, Button, IconButton, WrapItem, Tooltip, Image, Badge } from "@chakra-ui/react";
import { configs, Content, MarkdownFile, useContent } from "shared/content/Content";
import { VolumeIcon } from "utils/Icons";
import logoImage from './logo.png';

interface Props {
    text: {
        mobile: string;
        desktop: string;
    };
}

export const LogoType: FC<Props> = ({ text }) => {
    const variant = useBreakpointValue({ base: text.mobile, md: text.desktop });
    const onPlay = () => {
        const audio = new Audio(configs.common.audioFile);
        audio.play();
    };
    const currentPage = useScroll();

    const toSection = (section: string, offset = 75) => {
        const element = document.getElementById(section);
        if (element) {
            const elementPosition = element.getBoundingClientRect().top + window.scrollY;
            const targetPosition = elementPosition - offset;
            window.scrollTo({ top: targetPosition, behavior: "smooth" });
        }
    };

    return (
        <Box onClick={() => toSection(HomeId)} transition="all 0.2s ease-in-out" _hover={{ cursor: "pointer", color: "primary.600" }}>
            
            <Text mt="-2" mb="-2" ml="2" fontSize={{ base: "50px", md: "50px" }}  >☁️</Text>
           

        </Box>
    );
};